-- Schema
CREATE TABLE Books (
  isbn VARCHAR(13) PRIMARY KEY,
  title VARCHAR(200) NOT NULL,
  author_id INT REFERENCES Authors(author_id)
);
CREATE TABLE Members (
  member_id INT PRIMARY KEY,
  name VARCHAR(100) NOT NULL
);
CREATE TABLE Loans (
  loan_id INT PRIMARY KEY,
  isbn VARCHAR(13) REFERENCES Books(isbn),
  member_id INT REFERENCES Members(member_id),
  loan_date DATE NOT NULL,
  due_date DATE NOT NULL,
  return_date DATE
);

CREATE TABLE Products (
  product_id INT PRIMARY KEY,
  name VARCHAR(200),
  price DECIMAL(10,2)
);
CREATE TABLE Categories (
  category_id INT PRIMARY KEY,
  name VARCHAR(100)
);
CREATE TABLE ProductCategories (
  product_id INT REFERENCES Products,
  category_id INT REFERENCES Categories,
  PRIMARY KEY (product_id, category_id)
);

-- Problem:
SELECT * FROM products
WHERE name LIKE '%phone%';
-- Leading % prevents index use!

-- Solution 1: Full-text index
CREATE FULLTEXT INDEX idx_ft_name ON products(name);
SELECT * FROM products WHERE MATCH(name) AGAINST('phone');

-- Solution 2: Reverse column + LIKE 'pattern%'
SELECT * FROM products WHERE REVERSE(name) LIKE 'enohp%';

BEGIN;
  UPDATE accounts SET balance = balance - 100
  WHERE account_id = 'A';

  UPDATE accounts SET balance = balance + 100
  WHERE account_id = 'B';
COMMIT;

-- If crash before COMMIT:
-- WAL recovery undoes both updates
-- If crash after COMMIT:
-- WAL recovery redoes both updates

-- Safe migration steps:
-- 1. Create new tables
CREATE TABLE user_profiles (
  user_id INT PRIMARY KEY REFERENCES users(id),
  bio TEXT,
  avatar_url VARCHAR(500)
);

-- 2. Migrate data
INSERT INTO user_profiles (user_id, bio)
SELECT id, bio FROM users WHERE bio IS NOT NULL;

-- 3. Verify data integrity
SELECT COUNT(*) FROM user_profiles;

-- 4. Remove columns (after verification)
ALTER TABLE users DROP COLUMN bio;

-- Shared schema multi-tenant
CREATE TABLE tenants (
  tenant_id INT PRIMARY KEY,
  name VARCHAR(100)
);

CREATE TABLE documents (
  id BIGINT PRIMARY KEY,
  tenant_id INT NOT NULL REFERENCES tenants,
  title VARCHAR(200),
  content TEXT,
  -- Partial index per tenant for performance
  INDEX idx_tenant (tenant_id, title)
);

-- Row-Level Security
CREATE POLICY tenant_isolation ON documents
  USING (tenant_id = current_tenant_id());
